mapper.select:
SELECT a.achievement_id AS achievementId, a.achievement_code AS code, a.name AS name, a.description AS description, a.icon AS icon, a.tier AS tier, a.category AS category, a.condition_value AS conditionValue, a.exp_reward AS expReward, CASE WHEN ua.id IS NOT NULL THEN TRUE ELSE FALSE END AS unlocked, ua.achieved_at AS achievedAt FROM biz_achievement a LEFT JOIN biz_user_achievement ua ON a.achievement_code = ua.achievement_code AND ua.user_id = #{userId} WHERE a.enabled = 1
AND a.category = #{category}
ORDER BY a.sort_order ASC
